INSERT INTO public.v2_curriculums (id, workspace_id, title, description, content_rich, type, module_name, due_date, video_url, quiz_data, assets_json, is_published, points_weight, created_at) VALUES ('9a02c6d3-6780-44d1-ab9b-32febe681c85', 'be0763e3-4df5-46ac-9f11-c80d007b1188', 'Post Test #1 -  Fundamental & Landscaping Socmed Specialist', NULL, '', 'post_test', 'Materi 1 - Fundamental & Landscaping Socmed Specialist', '2026-03-30 16:00:00+00', '', '{"questions": [{"id": 1774768550950, "text": "1. Seorang Social Media Specialist harus memperhatikan beberapa hal berikut ini, kecuali ..", "correct": 3, "options": ["Tidak Fokus sama konten", "Socmed yang efektif berawal dari strategi yang baik", "Bukan cuma asal posting", "Harus fokus target FYP"]}, {"id": 1774768551846, "text": "2. Social Media Specialist punya banyak roles, Salah satunya adalah ..", "correct": 2, "options": ["UI Designer", "Content Writter", "Content Creator", "Scriptwriter"]}, {"id": 1774768552484, "text": "3. Jumlah Unique Person yang melihat konten kamu adalah istilah dari ..", "correct": 3, "options": ["Impression", "Engagement", "Persona", "Reach"]}, {"id": 1774768552822, "text": "4. Funnel yang bertujuan untuk menyebarkan konten dan membuat audeince aware terhadap produk kita adalah tahapan funnel ...", "correct": 3, "options": ["Consideration", "Interest", "Retention", "Awareness"]}, {"id": 1774768553162, "text": "5. Cara menentukan content goals dan KPI dari sebuah social media biasanya menggunakan metode ...", "correct": 3, "options": ["SWOT Analysis", "Umbrella Marketing", "TOWS Analysis", "SMART Analysis"]}, {"id": 1774768553480, "text": "6. Di dalam proses ideation, terdapat hal yang  harus dibangun untuk membuat merek/produk berbeda yang ditunjukkan di situs web atau pengetahuan produk, hal ini disebut dengan..", "correct": 0, "options": ["Unique Selling Point", "Unique Story Point", "Content Calender", "SWOT Analysis"]}, {"id": 1774768553795, "text": "7. Yang bukan termasuk alur dalam pembuatan konten yaitu..", "correct": 3, "options": ["Ideation", "Content Calendar", "Review", "Advertising"]}, {"id": 1774768554217, "text": "8. Dalam membuat content pillar terdapat beberapa proses yang harus dilakukan. Yang tidak termasuk ke dalam proses pembuatan content pillar yaitu...", "correct": 3, "options": ["Pahami Produknya", "Identifikasi kebutuhan Audience", "Riset Keyword", "Cari kesalahan kompetitor"]}, {"id": 1774768554513, "text": "9. Berikut hal-hal yang membuat content pillar penting dilakukan untuk mengembangkan sosial media, kecuali..", "correct": 2, "options": ["Memudahkan untuk membuat konten selama 1 bulan", "Membantu menonjolkan USP", "Membantu mengembangkan produk kompetitor", "Membantu merek menonjolkan Value"]}, {"id": 1774768554841, "text": "10. Urutkan Fase pembuatan konten dibawah ini, manakah urutan yang tepat?", "correct": 3, "options": ["Content Plan - Phasing - Timeline - Breakdown - Scheduling", "Content Phasing - Timeline - Planing - Breakdown - Scheduling", "Content Timeline - Planing - Breakdown - Phasing - Scheduling", "Content Breakdown - Phasing - Timeline - Planning - Scheduling"]}]}', '[]', 't', '10', '2026-03-29 07:33:55.720883+00') ON CONFLICT DO NOTHING;
